const items = $('Postgres - Select Exportable Leads').all();

const leadList = items.map(item => {
  const r = item.json;
  return {
    email: r.email,
    first_name: r.business_name || '',
    company: r.business_name || '',
    website: r.website || '',
    domain: r.domain || ''
  };
});

const ids = items.map(item => item.json.id);

return [{
  json: {
    lead_list: leadList,
    lead_ids: ids,
    count: leadList.length
  }
}];

const apiResponse = $input.first().json;
const payload = $('Code - Build Smartlead Payload').first().json;
const leadList = payload.lead_list;
const leadIds = payload.lead_ids;
const totalCount = payload.count;

// Smartlead POST /campaigns/{id}/leads returns:
// { upload_count: N, ... } or an array of per-lead results,
// or { error: '...' } on failure.
// We must only mark leads as exported if we can confirm per-lead success.

// Hard fail: API returned an error field
if (!apiResponse || apiResponse.error) {
  return [{ json: { _success: false, _confirmed_ids: [], _failed_count: totalCount } }];
}

// Try to extract per-lead confirmation from response.
// Smartlead may return an array of results with email + status,
// or a simple { upload_count } summary.
const results = Array.isArray(apiResponse) ? apiResponse
  : Array.isArray(apiResponse.data) ? apiResponse.data
  : Array.isArray(apiResponse.results) ? apiResponse.results
  : null;

if (results && results.length > 0) {
  // Per-lead results available — match back to IDs by email
  const emailToId = new Map();
  for (let i = 0; i < leadList.length; i++) {
    emailToId.set(leadList[i].email, leadIds[i]);
  }

  const confirmedIds = [];
  for (const r of results) {
    const email = (r.email || '').trim().toLowerCase();
    const status = (r.status || r.upload_status || '').toLowerCase();
    // Accept only explicitly successful statuses
    if (email && emailToId.has(email) && (status === 'uploaded' || status === 'success' || status === 'added')) {
      confirmedIds.push(emailToId.get(email));
    }
  }

  const failedCount = totalCount - confirmedIds.length;
  return [{ json: { _success: confirmedIds.length > 0, _confirmed_ids: confirmedIds, _failed_count: failedCount } }];
}

// No per-lead results — check for bulk upload_count
if (typeof apiResponse.upload_count === 'number' && apiResponse.upload_count === totalCount) {
  // Bulk confirmation matches exactly — safe to proceed
  return [{ json: { _success: true, _confirmed_ids: leadIds, _failed_count: 0 } }];
}

// Cannot confirm per-lead success — treat entire batch as unconfirmed
return [{ json: { _success: false, _confirmed_ids: [], _failed_count: totalCount } }];

const rows = $input.all().map(item => item.json).filter(r => r.id);
const failedCount = $('Code - Check API Response').first().json._failed_count || 0;

return [{
  json: {
    exported_count: rows.length,
    failed_count: failedCount,
    rows: rows
  }
}];

const payload = $('Code - Build Smartlead Payload').first().json;

return [{
  json: {
    exported_count: 0,
    failed_count: payload.count,
    rows: []
  }
}];
